using UnityEngine;
using UnityEngine.InputSystem;

/// <summary>
/// 3인칭 RPG 플레이어 컨트롤러.
/// CharacterController를 사용하여 카메라 기준 이동, 점프, 달리기, 웅크리기를 처리합니다.
/// </summary>
[RequireComponent(typeof(CharacterController))]
public sealed class PlayerController : MonoBehaviour
{
    // ─── 이동 설정 ───────────────────────────────────────────────────────────────

    [Header("이동 설정")]
    [Tooltip("걷기 속도 (m/s)")]

// ═══════════════════════════════════════════════════════════════════════════════
// PlayerAnimatorController.cs
// 3인칭 RPG 플레이어 애니메이터 브릿지
// PlayerController의 상태를 읽어 Animator 파라미터를 갱신합니다.
// ═══════════════════════════════════════════════════════════════════════════════

using UnityEngine;
using UnityEngine.InputSystem;

/// <summary>
/// 플레이어 애니메이터 브릿지.
/// PlayerController의 공개 프로퍼티를 읽어 Animator 파라미터를 갱신합니다.
/// 이동 로직을 중복 구현하지 않으며, 공격 트리거만 직접 입력을 처리합니다.
/// </summary>
[RequireComponent(typeof(Animator))]
[RequireComponent(typeof(PlayerController))]
public sealed class PlayerAnimatorController : MonoBehaviour
{
    // ─── 애니메이션 스무딩 설정 ──────────────────────────────────────────────────

// ═══════════════════════════════════════════════════════════════════════════════
// PlayerCameraController.cs
// 3인칭 RPG 카메라 피벗 컨트롤러
// Cinemachine 3 ThirdPersonFollow 패턴을 위한 Follow Target 회전 처리
// ═══════════════════════════════════════════════════════════════════════════════

using Unity.Cinemachine;
using UnityEngine;
using UnityEngine.InputSystem;

/// <summary>
/// 3인칭 RPG 카메라 컨트롤러.
/// Cinemachine CinemachineCamera가 추적할 CameraFollowTarget 자식 트랜스폼을 생성하고,
/// 마우스 입력으로 수평/수직 궤도 회전을 처리합니다.
/// 플레이어 회전은 PlayerController가 이동 방향 기준으로 처리합니다.
/// </summary>
[RequireComponent(typeof(PlayerController))]
public sealed class PlayerCameraController : MonoBehaviour
{
    // ─── 감도 설정 ───────────────────────────────────────────────────────────────

using UnityEngine;
using UnityEditor;
using UnityEngine.InputSystem;

/// <summary>
/// 바바리안 캐릭터의 InputActionReference를 자동으로 연결하는 일회성 유틸리티.
/// </summary>
public static class ConnectBabarianInputs
{
    private const string INPUT_ACTIONS_PATH = "Assets/InputSystem_Actions.inputactions";

    [MenuItem("Tools/Connect Babarian Inputs")]
    public static void Execute()
    {
        // ── InputActionAsset 로드 ──
        InputActionAsset inputActions = AssetDatabase.LoadAssetAtPath<InputActionAsset>(INPUT_ACTIONS_PATH);
        if (inputActions == null)
        {
            Debug.LogError("[ConnectInputs] InputSystem_Actions.inputactions를 찾을 수 없습니다.");
            return;

