// ═══════════════════════════════════════════════════════════════════════════════
// PlayerController.cs
// 3인칭 RPG 플레이어 이동 컨트롤러
// CharacterController 기반 이동, 점프, 달리기, 웅크리기 처리
// ═══════════════════════════════════════════════════════════════════════════════

using UnityEngine;
using UnityEngine.InputSystem;

/// <summary>
/// 3인칭 RPG 플레이어 컨트롤러.
/// CharacterController를 사용하여 카메라 기준 이동, 점프, 달리기, 웅크리기를 처리합니다.
/// </summary>
[RequireComponent(typeof(CharacterController))]
public sealed class PlayerController : MonoBehaviour
{
    // ─── 이동 설정 ───────────────────────────────────────────────────────────────

    [Header("이동 설정")]
    [Tooltip("걷기 속도 (m/s)")]
    [SerializeField] private float _walkSpeed = 4f;

    [Tooltip("달리기 속도 (m/s)")]
    [SerializeField] private float _sprintSpeed = 7f;

    [Tooltip("이동 방향으로 회전하는 속도 (도/초 기반 Slerp 계수)")]
    [SerializeField] private float _rotationSpeed = 10f;

    // ─── 점프 / 중력 설정 ────────────────────────────────────────────────────────

    [Header("점프 / 중력 설정")]
    [Tooltip("점프 높이 (m)")]
    [SerializeField] private float _jumpHeight = 1.2f;

    [Tooltip("중력 가속도 (음수, m/s²)")]
    [SerializeField] private float _gravity = -15f;

    [Tooltip("최대 낙하 속도 (음수, m/s)")]
    [SerializeField] private float _terminalVelocity = -40f;

    // ─── 웅크리기 설정 ───────────────────────────────────────────────────────────

    [Header("웅크리기 설정")]
    [Tooltip("기본 CharacterController 높이 (m)")]
    [SerializeField] private float _standingHeight = 1.8f;

    [Tooltip("웅크리기 시 CharacterController 높이 (m)")]
    [SerializeField] private float _crouchHeight = 1.0f;

    [Tooltip("웅크리기 시 이동 속도 배율")]
    [SerializeField] private float _crouchSpeedMultiplier = 0.5f;

    // ─── 입력 액션 레퍼런스 ──────────────────────────────────────────────────────

    [Header("입력 액션 레퍼런스")]
    [Tooltip("이동 입력 (Vector2)")]
    [SerializeField] private InputActionReference _moveAction;

    [Tooltip("점프 입력 (Button)")]
    [SerializeField] private InputActionReference _jumpAction;

    [Tooltip("달리기 입력 (Button)")]
    [SerializeField] private InputActionReference _sprintAction;

    [Tooltip("웅크리기 입력 (Button)")]
    [SerializeField] private InputActionReference _crouchAction;

    // ─── 내부 컴포넌트 참조 ──────────────────────────────────────────────────────

    private CharacterController _characterController;
    private Camera _mainCamera;

    // ─── 내부 상태 변수 ──────────────────────────────────────────────────────────

    private Vector2 _moveInput;
    private float _verticalVelocity;
    private bool _isGrounded;
    private bool _isSprinting;
    private bool _isCrouching;
    private bool _isJumping;

    // 웅크리기 토글 처리용
    private bool _crouchPressed;

    // 스케일 보정 계수 (모델이 0.01 스케일 등으로 임포트된 경우 CC 로컬 값을 보정)
    private float _localScaleInverse = 1f;

    // ─── 공개 읽기 전용 프로퍼티 (애니메이터 브릿지용) ──────────────────────────

    /// <summary>현재 이동 입력 값 (Vector2)</summary>
    public Vector2 MoveInput => _moveInput;

    /// <summary>현재 실제 이동 속도 (m/s)</summary>
    public float MoveSpeed { get; private set; }

    /// <summary>지면 접촉 여부</summary>
    public bool IsGrounded => _isGrounded;

    /// <summary>달리기 중 여부</summary>
    public bool IsSprinting => _isSprinting;

    /// <summary>웅크리기 중 여부</summary>
    public bool IsCrouching => _isCrouching;

    /// <summary>점프 중 여부 (공중에 있고 상승 중)</summary>
    public bool IsJumping => _isJumping;

    // ─── Unity 생명주기 ──────────────────────────────────────────────────────────

    private void Awake()
    {
        _characterController = GetComponent<CharacterController>();

        // 오브젝트 스케일에 따른 CC 치수 보정 계수 계산
        _localScaleInverse = 1f / Mathf.Max(transform.lossyScale.y, 0.001f);

        ApplyCharacterDimensions(_standingHeight);
    }

    /// <summary>
    /// CharacterController의 높이/센터/반지름을 오브젝트 스케일에 맞게 설정합니다.
    /// 직렬화된 높이 값은 월드 단위(m)로 유지하면서, CC 로컬 값을 스케일에 맞게 변환합니다.
    /// </summary>
    private void ApplyCharacterDimensions(float worldHeight)
    {
        float localHeight = worldHeight * _localScaleInverse;
        _characterController.height = localHeight;
        _characterController.center = new Vector3(0f, localHeight * 0.5f, 0f);
        _characterController.radius = localHeight * 0.15f;
    }

    private void Start()
    {
        _mainCamera = Camera.main;

        // 커서 잠금
        Cursor.lockState = CursorLockMode.Locked;
        Cursor.visible = false;
    }

    private void OnEnable()
    {
        if (_moveAction != null)   _moveAction.action.Enable();
        if (_jumpAction != null)   _jumpAction.action.Enable();
        if (_sprintAction != null) _sprintAction.action.Enable();
        if (_crouchAction != null)
        {
            _crouchAction.action.Enable();
            _crouchAction.action.performed += OnCrouchPerformed;
        }
    }

    private void OnDisable()
    {
        if (_moveAction != null)   _moveAction.action.Disable();
        if (_jumpAction != null)   _jumpAction.action.Disable();
        if (_sprintAction != null) _sprintAction.action.Disable();
        if (_crouchAction != null)
        {
            _crouchAction.action.performed -= OnCrouchPerformed;
            _crouchAction.action.Disable();
        }
    }

    private void Update()
    {
        ReadInput();
        HandleGroundCheck();
        HandleGravity();
        HandleJump();
        HandleCrouch();
        HandleMovement();
    }

    // ─── 입력 처리 ───────────────────────────────────────────────────────────────

    /// <summary>매 프레임 입력 값을 읽어 내부 변수에 저장합니다.</summary>
    private void ReadInput()
    {
        _moveInput  = _moveAction  != null ? _moveAction.action.ReadValue<Vector2>()  : Vector2.zero;
        _isSprinting = _sprintAction != null && _sprintAction.action.IsPressed() && !_isCrouching;
    }

    /// <summary>웅크리기 버튼 performed 콜백 — 토글 방식으로 처리합니다.</summary>
    private void OnCrouchPerformed(InputAction.CallbackContext ctx)
    {
        _crouchPressed = true;
    }

    // ─── 지면 체크 ───────────────────────────────────────────────────────────────

    /// <summary>CharacterController.isGrounded를 사용하여 지면 접촉 여부를 갱신합니다.</summary>
    private void HandleGroundCheck()
    {
        _isGrounded = _characterController.isGrounded;

        // 지면에 있을 때 작은 음수 속도를 유지하여 isGrounded 안정화
        if (_isGrounded && _verticalVelocity < 0f)
        {
            _verticalVelocity = -2f;
            _isJumping = false;
        }
    }

    // ─── 중력 처리 ───────────────────────────────────────────────────────────────

    /// <summary>중력을 적용하여 수직 속도를 갱신합니다. 터미널 속도를 초과하지 않습니다.</summary>
    private void HandleGravity()
    {
        if (!_isGrounded)
        {
            _verticalVelocity += _gravity * Time.deltaTime;
            _verticalVelocity = Mathf.Max(_verticalVelocity, _terminalVelocity);
        }
    }

    // ─── 점프 처리 ───────────────────────────────────────────────────────────────

    /// <summary>점프 입력을 감지하여 수직 속도를 설정합니다.</summary>
    private void HandleJump()
    {
        if (_jumpAction == null) return;

        if (_jumpAction.action.WasPressedThisFrame() && _isGrounded && !_isCrouching)
        {
            // v = sqrt(h * -2 * g)
            _verticalVelocity = Mathf.Sqrt(_jumpHeight * -2f * _gravity);
            _isJumping = true;
        }
    }

    // ─── 웅크리기 처리 ───────────────────────────────────────────────────────────

    /// <summary>웅크리기 토글 및 CharacterController 높이 조정을 처리합니다.</summary>
    private void HandleCrouch()
    {
        if (!_crouchPressed) return;
        _crouchPressed = false;

        _isCrouching = !_isCrouching;

        ApplyCharacterDimensions(_isCrouching ? _crouchHeight : _standingHeight);
    }

    // ─── 이동 처리 ───────────────────────────────────────────────────────────────

    /// <summary>
    /// 카메라 기준 이동 방향을 계산하고 CharacterController를 이동시킵니다.
    /// 이동 방향으로 플레이어를 부드럽게 회전합니다.
    /// </summary>
    private void HandleMovement()
    {
        // 목표 속도 계산
        float targetSpeed = 0f;
        if (_moveInput.sqrMagnitude > 0.01f)
        {
            if (_isCrouching)
                targetSpeed = _walkSpeed * _crouchSpeedMultiplier;
            else if (_isSprinting)
                targetSpeed = _sprintSpeed;
            else
                targetSpeed = _walkSpeed;
        }

        // 속도 스무딩 (애니메이터 브릿지용)
        MoveSpeed = Mathf.MoveTowards(MoveSpeed, targetSpeed, Time.deltaTime * 10f);

        // 카메라 기준 이동 방향 계산
        Vector3 moveDirection = Vector3.zero;
        if (_moveInput.sqrMagnitude > 0.01f && _mainCamera != null)
        {
            // 카메라 forward/right에서 Y 성분 제거 후 정규화
            Vector3 camForward = _mainCamera.transform.forward;
            Vector3 camRight   = _mainCamera.transform.right;
            camForward.y = 0f;
            camRight.y   = 0f;
            camForward.Normalize();
            camRight.Normalize();

            moveDirection = (camForward * _moveInput.y + camRight * _moveInput.x).normalized;
        }

        // 이동 방향으로 플레이어 회전 (Slerp)
        if (moveDirection.sqrMagnitude > 0.01f)
        {
            Quaternion targetRotation = Quaternion.LookRotation(moveDirection);
            transform.rotation = Quaternion.Slerp(
                transform.rotation,
                targetRotation,
                _rotationSpeed * Time.deltaTime
            );
        }

        // CharacterController 이동 적용
        Vector3 velocity = moveDirection * MoveSpeed;
        velocity.y = _verticalVelocity;
        _characterController.Move(velocity * Time.deltaTime);
    }
}

